import{_ as B,C as o,o as r,c as l,a2 as a,E as t,j as e,a as n}from"./chunks/framework.DnrXFDHb.js";const C=JSON.parse('{"title":"演进笔记：先治理，再谈更大的自动化","description":"","frontmatter":{},"headers":[],"relativePath":"agent/evolution-notes.md","filePath":"agent/evolution-notes.md","lastUpdated":1782828436000}'),i={name:"agent/evolution-notes.md"};function p(s,E,d,F,h,u){const A=o("Mermaid");return r(),l("div",null,[E[0]||(E[0]=a('<h1 id="演进笔记-先治理-再谈更大的自动化" tabindex="-1">演进笔记：先治理，再谈更大的自动化 <a class="header-anchor" href="#演进笔记-先治理-再谈更大的自动化" aria-label="Permalink to &quot;演进笔记：先治理，再谈更大的自动化&quot;">​</a></h1><p>我现在对 Agent 系统演进的判断比以前保守很多。</p><p>以前总觉得下一步是更多模型、更多工具、更多 Agent、更复杂的自动化。后来发现，能力越多，治理压力越大。真正限制系统的，往往不是模型不够聪明，而是状态、权限、成本、隔离和可观测性不够。</p><h2 id="不急着做的事" tabindex="-1">不急着做的事 <a class="header-anchor" href="#不急着做的事" aria-label="Permalink to &quot;不急着做的事&quot;">​</a></h2><p>不急着做完整多 Agent Runtime。远端 handoff 有用，但它不等于完整多 Agent。真正的多 Agent 还要处理父子任务、取消传播、权限传递、上下文边界、子运行可视化。</p><p>不急着做复杂 Graph。Graph 有价值，但要建立在状态、事件和幂等之上。</p><p>不急着接更多知识源。没有评测、rerank、权限过滤和记忆治理，更多数据只会带来更多噪声。</p><p>不急着开放所有工具生态。工具、Skill、远端 Agent 越开放，供应链和审计压力越大。</p><h2 id="更值得优先补的能力" tabindex="-1">更值得优先补的能力 <a class="header-anchor" href="#更值得优先补的能力" aria-label="Permalink to &quot;更值得优先补的能力&quot;">​</a></h2>',9)),t(A,{code:"flowchart%20TD%0A%20%20%20%20Base%5B%22%E5%BD%93%E5%89%8D%20Agent%20Runtime%22%5D%20--%3E%20Reliability%5B%22%E5%8F%AF%E9%9D%A0%E6%80%A7%3Cbr%2F%3E%E7%BB%88%E6%80%81%E3%80%81%E5%8F%96%E6%B6%88%E3%80%81%E8%B6%85%E6%97%B6%E3%80%81%E5%B9%82%E7%AD%89%22%5D%0A%20%20%20%20Base%20--%3E%20ToolGov%5B%22%E5%B7%A5%E5%85%B7%E6%B2%BB%E7%90%86%3Cbr%2F%3E%E5%AE%A1%E6%89%B9%E3%80%81%E9%A3%8E%E9%99%A9%E3%80%81%E9%85%8D%E9%A2%9D%E3%80%81%E5%AE%A1%E8%AE%A1%22%5D%0A%20%20%20%20Base%20--%3E%20Knowledge%5B%22%E7%9F%A5%E8%AF%86%E8%B4%A8%E9%87%8F%3Cbr%2F%3EHybrid%20Retrieval%E3%80%81Rerank%E3%80%81%E8%AF%84%E6%B5%8B%22%5D%0A%20%20%20%20Base%20--%3E%20SandboxOps%5B%22%E6%B2%99%E7%AE%B1%E8%BF%90%E8%90%A5%3Cbr%2F%3EWarm%20Pool%E3%80%81%E8%B5%84%E6%BA%90%E3%80%81%E7%BD%91%E7%BB%9C%E3%80%81%E5%9B%9E%E6%94%B6%22%5D%0A%20%20%20%20Base%20--%3E%20MultiAgent%5B%22%E5%A4%9A%20Agent%20%E8%BE%B9%E7%95%8C%3Cbr%2F%3E%E5%AD%90%E8%BF%90%E8%A1%8C%E3%80%81%E6%9D%83%E9%99%90%E3%80%81%E5%8F%96%E6%B6%88%E4%BC%A0%E6%92%AD%22%5D%0A%20%20%20%20Base%20--%3E%20Observability%5B%22%E5%B9%B3%E5%8F%B0%E5%8F%AF%E8%A7%82%E6%B5%8B%3Cbr%2F%3E%E4%BA%8B%E4%BB%B6%E3%80%81%E5%BB%B6%E8%BF%9F%E3%80%81%E5%A4%B1%E8%B4%A5%E3%80%81%E6%88%90%E6%9C%AC%22%5D%0A"}),E[1]||(E[1]=e("p",null,"可靠性是第一优先级。任务终态、取消、超时、事件一致性、工具幂等，这些不稳，后面都会反复返工。",-1)),E[2]||(E[2]=e("p",null,"工具治理要加强。审批、风险等级、配额、审计、签名、版本，这些决定工具生态能不能开放。",-1)),E[3]||(E[3]=e("p",null,"知识质量要能评估。混合检索、rerank、引用、评测集、记忆生命周期，比继续接更多数据源更重要。",-1)),E[4]||(E[4]=e("p",null,"沙箱要从“能跑代码”走向“能运营代码执行”。warm pool、资源限制、网络策略、健康检查、会话回收，都是生产问题。",-1)),E[5]||(E[5]=e("h2",{id:"演进路线",tabindex:"-1"},[n("演进路线 "),e("a",{class:"header-anchor",href:"#演进路线","aria-label":'Permalink to "演进路线"'},"​")],-1)),t(A,{code:"timeline%0A%20%20%20%20title%20Agent%20%E7%B3%BB%E7%BB%9F%E6%BC%94%E8%BF%9B%E8%8A%82%E5%A5%8F%0A%20%20%20%20%E7%9F%AD%E6%9C%9F%20%3A%20%E7%BB%88%E6%80%81%E4%B8%80%E8%87%B4%E6%80%A7%0A%20%20%20%20%20%20%20%20%20%3A%20%E5%B7%A5%E5%85%B7%E5%B9%82%E7%AD%89%0A%20%20%20%20%20%20%20%20%20%3A%20%E6%B2%99%E7%AE%B1%E5%81%A5%E5%BA%B7%E6%A3%80%E6%9F%A5%0A%20%20%20%20%20%20%20%20%20%3A%20%E5%86%85%E9%83%A8%E6%8E%A5%E5%8F%A3%E5%AE%89%E5%85%A8%0A%20%20%20%20%E4%B8%AD%E6%9C%9F%20%3A%20%E5%B7%A5%E5%85%B7%E6%B2%BB%E7%90%86%E5%8F%B0%0A%20%20%20%20%20%20%20%20%20%3A%20Skill%20%E7%89%88%E6%9C%AC%E7%AE%A1%E7%90%86%0A%20%20%20%20%20%20%20%20%20%3A%20%E7%9F%A5%E8%AF%86%E8%AF%84%E6%B5%8B%0A%20%20%20%20%20%20%20%20%20%3A%20Provider%20%E7%8A%B6%E6%80%81%E5%8F%AF%E8%A7%82%E6%B5%8B%0A%20%20%20%20%E9%95%BF%E6%9C%9F%20%3A%20%E8%BD%BB%E9%87%8F%20Graph%20Runtime%0A%20%20%20%20%20%20%20%20%20%3A%20%E5%AE%8C%E6%95%B4%20Supervisor%0A%20%20%20%20%20%20%20%20%20%3A%20%E5%A4%9A%20Agent%20%E4%BB%BB%E5%8A%A1%E6%A0%91%0A%20%20%20%20%20%20%20%20%20%3A%20%E8%B7%A8%20Agent%20%E6%9D%83%E9%99%90%E4%BC%A0%E9%80%92%0A"}),E[6]||(E[6]=a('<p>我不想再把“看起来高级”作为优先级。优先级应该来自失败模式：哪里最容易失控，哪里最难排查，哪里副作用最大，就先治理哪里。</p><h2 id="踩过的坑" tabindex="-1">踩过的坑 <a class="header-anchor" href="#踩过的坑" aria-label="Permalink to &quot;踩过的坑&quot;">​</a></h2><p>第一个坑，是把未来能力写成当前能力。比如“支持多 Agent”这句话，如果只是能 handoff，和完整 Supervisor Runtime 是两回事。</p><p>第二个坑，是为了高级感过早抽象。Graph、Supervisor、工具市场都很有吸引力，但时机不对会变成负担。</p><p>第三个坑，是只看功能不看运营。能跑一次和能长期运营，是两件事。</p><p>第四个坑，是缺少端到端观测。Agent 问题经常跨模型、工具、事件、前端、后台任务。没有观测，很难定位。</p><p>第五个坑，是开放生态带来的供应链风险。MCP、Skill、远端 Agent 越开放，权限、签名、版本、审计越重要。</p><h2 id="现在的记录" tabindex="-1">现在的记录 <a class="header-anchor" href="#现在的记录" aria-label="Permalink to &quot;现在的记录&quot;">​</a></h2><p>如果再做一年，我会按这个节奏：</p><p>短期补可靠性和测试。中期做治理产品化。长期再做更强编排。</p><p>一句话总结：Agent 系统下一阶段不是更会聊天，而是更会治理。能限制、能隔离、能恢复、能审计，才敢让它做更多事。</p><h2 id="podcast-提纲" tabindex="-1">Podcast 提纲 <a class="header-anchor" href="#podcast-提纲" aria-label="Permalink to &quot;Podcast 提纲&quot;">​</a></h2><ol><li>为什么我现在更重视治理而不是功能堆叠。</li><li>多 Agent 为什么不能只看 handoff。</li><li>Graph 应该什么时候引入。</li><li>RAG 为什么要从检索走向评测。</li><li>Tool 和 Skill 的供应链风险。</li><li>沙箱从执行能力到运营能力的差距。</li><li>未来一年我会优先补哪些基础。</li></ol>',13))])}const D=B(i,[["render",p]]);export{C as __pageData,D as default};
